import React, { useState } from 'react';

const App = () => {
  const [otpValue, setOtpValue] = useState('');
  const [mfaSetting, setMfaSetting] = useState('');
  const [queryTest, setQueryTest] = useState('');

  const handleOtpChange = (event) => {
    setOtpValue(event.target.value);
  };

  const handleMfaChange = (event) => {
    setMfaSetting(event.target.value);
  };

  const handleQueryTest = (event) => {
    setQueryTest(event.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-md w-3/4">
        <div className="flex flex-wrap justify-center mb-4">
          <label className="block w-1/2 mb-2" htmlFor="otp-input">
            OTP:
          </label>
          <input
            className="block w-1/2 px-2 py-1 text-white bg-transparent border-b border-white focus:border-[#C06C88] focus:ring-[#C06C88] focus:ring-2 focus:outline-none" type="text" id="otp-input" value={otpValue} onChange={handleOtpChange} placeholder="Input OTP"/>
        </div>
        <div className="flex flex-wrap justify-center mb-4">
          <label className="block w-1/2 mb-2" htmlFor="mfa-select">
            MFA Setting:
          </label>
          <select
            className="block w-1/2 px-2 py-1 text-white bg-transparent border-b border-white focus:border-[#C06C88] focus:ring-[#C06C88] focus:ring-2 focus:outline-none" id="mfa-select" value={mfaSetting} onChange={handleMfaChange}>
            <option value="sms">SMS</option>
            <option value="authenticator">Authenticator App</option>
            <option value="token">Hardware Token</option>
          </select>
        </div>
        <div className="flex flex-wrap justify-center mb-4">
          <label className="block w-1/2 mb-2" htmlFor="query-playground">
            Query Playground:
          </label>
          <textarea
            className="block w-1/2 px-2 py-1 text-white bg-transparent border-b border-white focus:border-[#C06C88] focus:ring-[#C06C88] focus:ring-2 focus:outline-none" id="query-playground" rows="4" cols="30" value={queryTest} onChange={handleQueryTest} placeholder="Test MFA settings and scenarios"/>
        </div>
        <button className="bg-[#C06C88] hover:bg-[#F7D2C4] text-[#B7D7CD] font-bold py-2 px-4 rounded" type="button">
          Submit OTP
        </button>
      </div>
    </div>
  );
};

export default App;
